      o1i = t0i;
      t0r = o2i;
      t0i = _mm256_xor_pd(o2r, sign_flip);
      o2r = t0r;
      o2i = t0i;
      t0r = _mm256_mul_pd(_mm256_sub_pd(o3i, o3r), sqrt2_inv);
      t0i = _mm256_xor_pd(_mm256_mul_pd(_mm256_add_pd(o3r, o3i), sqrt2_inv), sign_flip);
